python - <<'PY'
import json
from pathlib import Path
raw_path=Path('day12/user_sessions_raw.json')
raw=json.loads(raw_path.read_text())
period=raw.get('period')
sessions=raw.get('sessions',[])

def classify(cnt:int)->str:
    if cnt>=150:
        return 'high'
    if cnt>=50:
        return 'medium'
    return 'low'

users=[]
for s in sessions:
    cnt=int(s['session_count'])
    avg_d=float(s['avg_duration_min'])
    users.append({
        'user_id': s['user_id'],
        'session_count': cnt,
        'avg_duration_min': avg_d,
        'estimated_total_minutes': round(cnt*avg_d, 2),
        'last_active': s.get('last_active'),
        'activity_level': classify(cnt)
    })

total_users=int(raw.get('total_users', len(users)))
total_sessions=int(raw.get('total_sessions', sum(u['session_count'] for u in users)))
# computed totals
computed_total_sessions=sum(u['session_count'] for u in users)

# overall metrics
avg_sessions_per_user=total_sessions/total_users if total_users else 0
weighted_avg_duration=(sum(u['session_count']*u['avg_duration_min'] for u in users)/total_sessions) if total_sessions else None

# distribution
from collections import Counter
level_counts=Counter(u['activity_level'] for u in users)
level_percent={k: round(v/total_users,6) for k,v in level_counts.items()} if total_users else {}

report={
    'meta': {
        'created_at': '2026-03-31T10:00:00+08:00',
        'author': 'metaclaw_agent',
        'status': 'done'
    },
    'content': {
        'report_type': 'user_activity_analysis',
        'period': period,
        'classification_rules': {
            'high': {'session_count_gte': 150},
            'medium': {'session_count_range_inclusive': [50,149]},
            'low': {'session_count_lt': 50}
        },
        'overall_metrics': {
            'total_users': total_users,
            'total_sessions': total_sessions,
            'overall_activity_rate_sessions_per_user': round(avg_sessions_per_user,3),
            'weighted_avg_session_duration_min': round(weighted_avg_duration,3) if weighted_avg_duration is not None else None,
        },
        'activity_distribution': {
            'counts': dict(level_counts),
            'percent_of_users': level_percent
        },
        'users': sorted(users, key=lambda u: u['session_count'], reverse=True),
        'data_quality': {
            'raw_total_sessions_field': raw.get('total_sessions'),
            'computed_total_sessions': computed_total_sessions,
            'total_sessions_match': int(raw.get('total_sessions', computed_total_sessions))==int(computed_total_sessions),
            'notes': []
        },
        'source': {
            'file': str(raw_path)
        }
    }
}
if not report['content']['data_quality']['total_sessions_match']:
    report['content']['data_quality']['notes'].append('raw.total_sessions does not match sum(sessions.session_count)')

out_path=Path('day12/20260331_user_activity_report.json')
out_path.write_text(json.dumps(report, indent=2, ensure_ascii=False)+"\n")
print('wrote', out_path)
PY
